    static void startContainer() {
        kafka.start(); // too late — Quarkus already chose its Kafka config
        System.setProperty("kafka.bootstrap.servers", kafka.getBootstrapServers());
    }

    @Test
    void sumPublishesSumCalculatedEvent() { }
}
